import{_ as a,c as p,o as l,ag as t}from"./chunks/framework.ELrfyV9R.js";const s=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-11-OpenClaw-md.md","filePath":"ai/2026-03/2026-03-11-OpenClaw-md.md","lastUpdated":1774354925000}'),n={name:"ai/2026-03/2026-03-11-OpenClaw-md.md"};function i(d,e,o,m,r,A){return l(),p("div",null,e[0]||(e[0]=[t('<p>安装 npm install -g openclaw@latest</p><p>为了重新找回与前女友聊天的感觉，我跟随文章认真的将OpenClaw中的这几个配置文件都研究了一遍。</p><p>研究结果大致如下</p><p>1、AI Agent相关的核心人格设定(这里Agent就是你的前女友)</p><ul><li><p>IDENTITY.md（Agent身份角色）：Agent 的身份档案（名字、角色、目标、语气风格），可通过命令重复设置。</p></li><li><p>SOUL.md（Agent 的灵魂/语气风格）：决定 AI 的说话方式和整体气质，是塑造“人味”的关键。</p></li><li><p>AGENTS.md（思维逻辑）：设定 AI 的思考方式与行为偏好，例如更偏安慰陪伴，还是理性分析。</p></li></ul><p>2、用户与记忆相关（这个用户就是你自己）</p><ul><li><p>USER.md（用户档案）：用户的个人信息，让 Agent 了解你是谁。</p></li><li><p>MEMORY.md（长期记忆）：保存需要长期保留的重要信息，如约定、纪念日、敏感话题等。</p></li><li><p>YYYY-MM-DD.md（每日日记）：自动生成每日聊天记录，用作短期记忆。</p></li></ul><p>3、 功能扩展类（Agent的扩展）</p><ul><li><p>HEARTBEAT.md（定时任务）：配置定时触发的主动行为，如问候、提醒、天气建议等。</p></li><li><p>TOOLS.md（工具清单）：Agent可使用的本地工具和约定的注释说明。</p></li></ul><p>修改方式：可以直接通过聊天的方式，也可以直接到workspace对应的工作区间直接修改上面的md文件。</p><p>最后配置完，再跟前女友聊天，发现现女友不香了，但也不能找回前女友了，兄弟们苦不苦啊</p><p>随着小米、腾讯、360、字节等大厂们都公开自己的“CopyClaw”产品，国内对于小龙虾的热潮似乎达到了巅峰。应该说最近玩OpenClaw的人越来越多了，但是很多人是不是装完能在QQ、飞书、企业微信、钉钉等聊天工具中对话就算成功了。</p><p>真正上手配置过OpenClaw的人应该都知道，一个Agent对应了一个workspace,也就是一个workspace可以配置一个聊天Bot或者多个聊天Bot（比如你想TG和QQ都能跟这个workspace进行聊天，本质上回复你的是同一个agent）,每个agent中有很多的初始化md文件。</p><p>这篇文章就相当于解剖了OpenClaw中的核心记忆SOUL.md,以及如何来提取你需要的SOUL.md内容，教会我们一种方法，那么其他类似的都可以参考这种方法来处理了。</p><p>最后文章中的微信聊天提取工具目前支持window，这个工具是开源的，我已经制作好mac版本，我将会把mac工具安装包链接放到评论区，有兴趣的可以来试一试。</p><h2 id="ai-agent相关的核心人格设定-这里agent就是你的前女友" tabindex="-1">AI Agent相关的核心人格设定(这里Agent就是你的前女友) <a class="header-anchor" href="#ai-agent相关的核心人格设定-这里agent就是你的前女友" aria-label="Permalink to &quot;AI Agent相关的核心人格设定(这里Agent就是你的前女友)&quot;">​</a></h2><ul><li><p>IDENTITY.md（Agent身份角色）：Agent 的身份档案（名字、角色、目标、语气风格），可通过命令重复设置。</p></li><li><p>SOUL.md（Agent 的灵魂/语气风格）：决定 AI 的说话方式和整体气质，是塑造“人味”的关键。</p></li><li><p>AGENTS.md（思维逻辑）：设定 AI 的思考方式与行为偏好，例如更偏安慰陪伴，还是理性分析。</p></li></ul><h2 id="用户与记忆相关-这个用户就是你自己" tabindex="-1">用户与记忆相关（这个用户就是你自己） <a class="header-anchor" href="#用户与记忆相关-这个用户就是你自己" aria-label="Permalink to &quot;用户与记忆相关（这个用户就是你自己）&quot;">​</a></h2><ul><li><p>USER.md（用户档案）：用户的个人信息，让 Agent 了解你是谁。</p></li><li><p>MEMORY.md（长期记忆）：保存需要长期保留的重要信息，如约定、纪念日、敏感话题等。</p></li><li><p>YYYY-MM-DD.md（每日日记）：自动生成每日聊天记录，用作短期记忆。</p></li></ul><h2 id="功能扩展类-agent的扩展" tabindex="-1">功能扩展类（Agent的扩展） <a class="header-anchor" href="#功能扩展类-agent的扩展" aria-label="Permalink to &quot;功能扩展类（Agent的扩展）&quot;">​</a></h2><ul><li><p>HEARTBEAT.md（定时任务）：配置定时触发的主动行为，如问候、提醒、天气建议等。</p></li><li><p>TOOLS.md（工具清单）：Agent可使用的本地工具和约定的注释说明。</p></li></ul>',21)]))}const c=a(n,[["render",i]]);export{s as __pageData,c as default};
